__global__ void compute_coeff_kernel(const float *J, float *dN, float *dS, float *dW, float *dE,
                                     float *c, int rows, int cols, float elem_9)
{
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    int i = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < rows && j < cols) {
        int k = i * cols + j;
        float Jc = J[k];

        int iN = (i == 0) ? 0 : (i - 1);
        int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
        int jW = (j == 0) ? 0 : (j - 1);
        int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

        float dn = J[iN * cols + j] - Jc;
        float ds = J[iS * cols + j] - Jc;
        float dw = J[i * cols + jW] - Jc;
        float de = J[i * cols + jE] - Jc;

        dN[k] = dn;
        dS[k] = ds;
        dW[k] = dw;
        dE[k] = de;

        float G2 = (dn * dn + ds * ds + dw * dw + de * de) / (Jc * Jc);
        float L = (dn + ds + dw + de) / Jc;

        float num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
        float den = 1.0f + (0.25f * L);
        float qsqr = num / (den * den);

        den = (qsqr - elem_9) / (elem_9 * (1.0f + elem_9));
        float ck = 1.0f / (1.0f + den);

        if (0.0f > ck) {
            ck = 0.0f;
        } else if (1.0f < ck) {
            ck = 1.0f;
        }

        c[k] = ck;
    }
}

__global__ void update_kernel(float *J, const float *c, const float *dN, const float *dS,
                              const float *dW, const float *dE, int rows, int cols, float lambda)
{
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    int i = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < rows && j < cols) {
        int k = i * cols + j;

        int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
        int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

        float cN = c[k];
        float cS = c[iS * cols + j];
        float cW = c[k];
        float cE = c[i * cols + jE];

        float D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];

        J[k] = J[k] + 0.25f * lambda * D;
    }
}

